    tags: [],
    youtube: 'https://www.youtube.com/watch?v=RAYv3n4q-Wc',
    ingredients: [
    { name: { en: 'Strong white bread flour', ro: 'faina alba de paine', ru: 'мука для хлеба', es: 'harina de fuerza' }, measure: '500g' },
    { name: { en: 'Caster Sugar', ro: 'zahar pudra fin', ru: 'мелкий сахар', es: 'azucar glass fino' }, measure: '70g' },
    { name: { en: 'Yeast', ro: 'drojdie', ru: 'дрожжи', es: 'levadura' }, measure: '10g' },
    { name: { en: 'Egg', ro: 'ou', ru: 'яйцо', es: 'huevo' }, measure: '2 Beaten' },
    { name: { en: 'Sunflower Oil', ro: 'ulei de floarea soarelui', ru: 'подсолнечное масло', es: 'aceite de girasol' }, measure: '70 ml' },
    { name: { en: 'Poppy Seeds', ro: 'seminte de mac', ru: 'маковые семена', es: 'semillas de amapola' }, measure: '1 tablespoon' }
    ],
